def _unique_preserve_order(values: list[str]) -> list[str]:
    """Deduplicate a list while preserving the first-seen order."""
    seen: set[str] = set()
    unique_values: list[str] = []
    for value in values:
        if value in seen:
            continue
        seen.add(value)
        unique_values.append(value)
    return unique_values


