    def _parse_score(self, response_text: str) -> float:
        """Parse an LLM score and clamp it to [0, 1]."""
        match = re.search(r"[-+]?\d*\.?\d+", response_text)
        if match is None:
            return float("nan")

        score = float(match.group())
        return max(0.0, min(1.0, score))

